#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10;

struct Edge{
    int to,id;
};

int n,m,d[N],p[N*4],now[3][N];
vector<Edge> e[3][N];

void dfs(int x,int lst){
    for(int i=now[lst][x];i<e[lst][x].size();i=now[lst][x]){
        Edge y=e[lst][x][i];
        now[lst][x]=i+1;
        if(!p[abs(y.id)]){
            p[abs(y.id)]=(y.id<0)+1;
            dfs(y.to,lst);
        }
    }
    lst=3-lst;
    for(int i=now[lst][x];i<e[lst][x].size();i=now[lst][x]){
        Edge y=e[lst][x][i];
        now[lst][x]=i+1;
        if(!p[abs(y.id)]){
            p[abs(y.id)]=(y.id<0)+1;
            dfs(y.to,lst);
        }
    }
}

inline int rd(){
    char ch=getchar();int r=0;
    while(ch<'0' || '9'<ch) ch=getchar();
    while('0'<=ch && ch<='9') r=(r<<3)+(r<<1)+ch-'0',ch=getchar();
    return r;
}

int main(){
    n=rd(),m=rd();
    for(int i=1;i<=m;i++){
        int u,v,w;
        u=rd(),v=rd(),w=rd();
        e[w][u].push_back({v,i});
        e[w][v].push_back({u,-i});
        d[u]++,d[v]++;
    }
    for(int i=1;i<=n;i++)
        if(d[i]%2){
            e[1][n+1].push_back({i,m+i});
            e[1][i].push_back({n+1,-m-i});
        }
    if(e[1][n+1].size())
        dfs(n+1,1);
    else
        dfs(1,1);
    for(int i=1;i<=m;i++)
        printf("%d",p[i]-1);
    return 0;
}
